{
  "summary": "This paper proposes language-based methods to approximate human similarity judgments across images, audio, and video modalities, significantly reducing the annotation cost from O(N²) to O(N). It introduces the STEP-Tag adaptive tagging pipeline and combines textual and DNN embeddings to improve similarity approximation, supported by extensive empirical evaluation over 600 pre-trained models and large-scale human data.",
  "strengths": [
    {
      "point": "Comprehensive empirical evaluation across multiple modalities and models",
      "evidence": "Evaluated 611 pre-trained models across images, audio, and video, collecting over 206,000 human judgments and textual descriptors."
    },
    {
      "point": "Novel adaptive tagging pipeline (STEP-Tag) for efficient, high-quality tag collection",
      "evidence": "STEP-Tag iteratively collects and filters tags, improving tag quality and diversity compared to baselines."
    },
    {
      "point": "Introduction of language-based similarity approximation methods reducing annotation complexity",
      "evidence": "Proposed O(N) methods using captions and tags to approximate human similarity, outperforming DNN-only approaches."
    },
    {
      "point": "Stacked embedding approach combining DNN and LLM embeddings for improved performance",
      "evidence": "Hybrid methods consistently outperform individual modalities in approximating human similarity judgments."
    },
    {
      "point": "Public release of large-scale datasets and code to facilitate reproducibility and further research",
      "evidence": "Released 206,339 human judgments and language data across three domains with detailed modeling results."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient engagement with prior language-based similarity literature",
      "evidence": "Key related works such as image-caption embeddings and CLIP-based zero-shot retrieval are not discussed or compared."
    },
    {
      "point": "Lack of ablation studies and quantitative justification for STEP-Tag design choices",
      "evidence": "No experiments varying iteration counts, tag quality thresholds, or diversity enforcement metrics are provided."
    },
    {
      "point": "Missing baselines using automated caption generation models",
      "evidence": "Evaluation omits automated captioning systems like CLIP-based image captioners or pretrained audio captioners."
    },
    {
      "point": "Overreliance on correlation metrics without downstream task evaluation",
      "evidence": "No reported retrieval precision, recall, clustering quality, or classification accuracy to demonstrate practical utility."
    },
    {
      "point": "Insufficient details on human annotation protocols and quality control",
      "evidence": "Annotation instructions, qualification criteria, compensation, attention checks, and inter-annotator agreement statistics are not described."
    },
    {
      "point": "Ambiguous explanation of stacked embedding hyperparameter tuning",
      "evidence": "Unclear how rescaling parameter is selected or optimized across modalities or datasets."
    },
    {
      "point": "No discussion of language biases and cultural effects in crowdsourced textual data",
      "evidence": "Potential demographic, linguistic, or cultural biases affecting similarity approximations are not acknowledged."
    },
    {
      "point": "Limited exploration of word-frequency analysis techniques",
      "evidence": "No comparative analysis of different WFA methods or sensitivity to tag vocabulary size and quality."
    },
    {
      "point": "Missing details on text preprocessing and embedding extraction procedures",
      "evidence": "No information on tokenization, stopword removal, embedding layers used, pooling strategies, or dimensionality."
    },
    {
      "point": "No qualitative error analysis or case studies illustrating failure modes",
      "evidence": "Lack of examples where language-based or DNN-based similarity diverge from human judgments."
    },
    {
      "point": "No consideration of temporal dynamics in audio and video modalities",
      "evidence": "Approach treats audio and video as static without addressing temporal structure."
    },
    {
      "point": "Limited discussion on STEP-Tag applicability beyond crowdsourcing",
      "evidence": "Feasibility in expert annotation or automated tag generation contexts is not addressed."
    },
    {
      "point": "No ablation on relative contributions of free-text captions versus tags",
      "evidence": "No experiments isolating captions-only, tags-only, or combined conditions to clarify cost-benefit trade-offs."
    },
    {
      "point": "No analysis of computational costs beyond human judgment scaling",
      "evidence": "Runtime, memory usage, and resource requirements for embedding extraction and similarity computation are not reported."
    },
    {
      "point": "Evaluation limited to curated datasets without noisy, ambiguous, or multi-label stimuli",
      "evidence": "Robustness to real-world challenging data is not assessed."
    },
    {
      "point": "Missing discussion of crowdsourcing worker demographics and ethical safeguards",
      "evidence": "No information on annotator demographics, compensation fairness, or data quality safeguards."
    },
    {
      "point": "Simplistic fusion of embeddings without exploring advanced integration techniques",
      "evidence": "No investigation of attention mechanisms, learned weighting, or multimodal transformers."
    }
  ],
  "questions": [
    {
      "question": "How does the proposed language-based similarity approximation compare empirically to automated caption generation baselines?",
      "motivation": "Including automated captioning baselines would clarify the trade-offs between human effort and automated scalability."
    },
    {
      "question": "What is the impact of modality-specific challenges on the quality and consistency of textual descriptors, especially for audio and video?",
      "motivation": "Understanding modality-specific difficulties is crucial for assessing the generalizability and robustness of the approach."
    },
    {
      "question": "How sensitive are the STEP-Tag pipeline’s performance gains to its design parameters such as iteration count and tag quality thresholds?",
      "motivation": "Ablation studies would inform the robustness and optimal configuration of the tagging pipeline."
    },
    {
      "question": "Can the stacked embedding approach be improved using more sophisticated fusion techniques beyond simple concatenation and rescaling?",
      "motivation": "Exploring advanced integration methods could yield better synergy between sensory and linguistic modalities."
    },
    {
      "question": "How do the proposed methods perform on downstream tasks like retrieval or classification compared to correlation metrics?",
      "motivation": "Demonstrating practical utility beyond correlation would strengthen the impact and applicability of the approach."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
